function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue == '') {
		return;
	}

	// STRY0071533 -  https://www.servicenowguru.com/scripting/client-scripts-scripting/client-side-dates-in-servicenow/
	// based on the article referenced above, this should work for the function below.
	// we can use the user's date and time format instead of forcing one.
	if(oldValue == newValue){
		return;
	}

	var get_suspense_date = g_form.getValue('suspense_date');
	var suspense_date = getDateFromFormat(get_suspense_date, g_user_date_time_format);
	if(suspense_date==0){
		suspense_date = new Date(get_suspense_date);
	}

	var newValueNumer = getDateFromFormat(newValue, g_user_date_time_format);
	var now = new Date(new Date().getTime());

	// NOTE: if we add a system setting or a Task setting for no Time, then we would set NOW to be just the date with time 00:00:00.  
	// The Suspense date would also need to chage to g_user_date_format.  But, it can be handled better using the client capabilities

	// STRY0072379
	if(g_scratchpad.suspenseDatesAndExpctedStartDatesMustBeInTheFuture == 'true'){
		if(newValueNumer < now){
			g_form.clearValue('extended_suspense_date');
			g_form.showErrorBox('extended_suspense_date','The Requested Suspense Date must be a date in the future.', true);
			return;
		}
	}
	if(newValueNumer <= suspense_date ){
		g_form.clearValue('extended_suspense_date');
		g_form.showErrorBox('extended_suspense_date','The Requested Suspense Date must be after the Suspense Date ' + g_form.getValue('suspense_date'), true);
		return;
	}

	// Time was added.  but, if we wanted to go back to the logic with time, this should set to the very end of the day.
	// var new_suspense_date = getDateFromFormat(g_form.getValue('extended_suspense_date'), g_user_date_format);
	// new_suspense_date = new Date(new_suspense_date + ((1000 * 60 * 60 * 23) + (1000 * 60 * 59) + (1000 * 59)  ));
	// g_form.setValue('extended_suspense_date', new_suspense_date);
	if(g_form.getValue('calchaschildren') > 0){
		var duration = g_form.getValue('calendar_duration');
		// if using date only, then uncomment.  Using time, stay with what is here
		// var extended_change = getDifferenceInDays(suspense_date, newValueNumer);
		var extended_change = suspense_date - newValueNumer;
		if (duration > 0){
			// if using date only, then uncomment.  Using time, stay with what is here
			//var percent = ((extended_change * 24)/duration)/100;
			var percent = ((extended_change)/duration)/100;
			g_form.setValue('suspense_change_type', 'percent');
			g_form.setValue('suspense_change', percent);
		}else{
			// if using days, then get difference in days
			extended_change = getDifferenceInDays(suspense_date, newValueNumer);
			g_form.setValue('suspense_change', extended_change);
			g_form.setValue('suspense_change_type', 'days');
		}
		alert("Extending the suspense date will effect all subtasks.");
	}	

